import { cookies } from "next/headers";
import Link from "next/link";
import { redirect } from "next/navigation";

const SALES_AGENT_COOKIE = "lead-scorer-sales-agent";

export default async function PipelinePage() {
  const cookieStore = await cookies();
  const selectedSalesAgent = cookieStore.get(SALES_AGENT_COOKIE)?.value;

  if (!selectedSalesAgent) {
    redirect("/");
  }

  return (
    <main className="min-h-screen bg-[linear-gradient(180deg,_#f4ede2,_#efe7db)] px-6 py-10 text-stone-900 sm:px-10 lg:px-16">
      <div className="mx-auto max-w-5xl space-y-8">
        <header className="rounded-[2rem] border border-stone-900/10 bg-white/85 px-8 py-8 shadow-[0_20px_60px_rgba(76,61,43,0.12)] backdrop-blur">
          <p className="text-sm font-medium uppercase tracking-[0.24em] text-stone-500">
            Pipeline
          </p>
          <div className="mt-4 flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
            <div>
              <h1 className="text-3xl font-semibold tracking-tight text-stone-950">
                {selectedSalesAgent}
              </h1>
              <p className="mt-2 max-w-2xl text-sm leading-6 text-stone-600">
                The selected salesperson was loaded from the login flow via a cookie,
                which keeps the pipeline page aware of who is currently signed in.
              </p>
            </div>
            <Link
              className="inline-flex items-center justify-center rounded-2xl border border-stone-300 px-4 py-2 text-sm font-medium text-stone-700 transition hover:border-stone-950 hover:text-stone-950"
              href="/"
            >
              Switch salesperson
            </Link>
          </div>
        </header>

        <section className="grid gap-4 md:grid-cols-3">
          <article className="rounded-[1.5rem] border border-stone-900/10 bg-stone-950 p-6 text-stone-50">
            <p className="text-sm uppercase tracking-[0.2em] text-amber-300/80">
              Session state
            </p>
            <p className="mt-4 text-2xl font-semibold">Ready</p>
            <p className="mt-2 text-sm leading-6 text-stone-300">
              The login choice is already available here for filtering and ranking the
              deals assigned to this salesperson.
            </p>
          </article>

          <article className="rounded-[1.5rem] border border-stone-900/10 bg-white/85 p-6">
            <p className="text-sm uppercase tracking-[0.2em] text-stone-500">
              Next step
            </p>
            <p className="mt-4 text-2xl font-semibold text-stone-950">
              Load open deals
            </p>
            <p className="mt-2 text-sm leading-6 text-stone-600">
              This page is now positioned to pull only the current salesperson&apos;s open
              opportunities from the pipeline dataset.
            </p>
          </article>

          <article className="rounded-[1.5rem] border border-stone-900/10 bg-white/85 p-6">
            <p className="text-sm uppercase tracking-[0.2em] text-stone-500">
              Explainability
            </p>
            <p className="mt-4 text-2xl font-semibold text-stone-950">Planned</p>
            <p className="mt-2 text-sm leading-6 text-stone-600">
              Score breakdowns can be attached to this view once the deal scoring
              module is added.
            </p>
          </article>
        </section>
      </div>
    </main>
  );
}